1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0], [1, 0],
6	  [-1, 1], [0, 1], [1, 1],
7	];
8	
9	const keyOf = (x: number, y: number): string => `${x},${y}`;
10	
11	const survivesOrIsBorn = (liveNeighbors: number, wasAlive: boolean): boolean =>
12	  liveNeighbors === 3 || (liveNeighbors === 2 && wasAlive);
13	
14	type NeighborTally = Map<string, { cell: Cell; liveNeighbors: number }>;
15	
16	function tallyLiveNeighbors(cells: Cell[]): NeighborTally {
17	  const tally: NeighborTally = new Map();
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const cell: Cell = [x + dx, y + dy];
21	      const key = keyOf(cell[0], cell[1]);
22	      const entry = tally.get(key);
23	      tally.set(key, { cell, liveNeighbors: (entry?.liveNeighbors ?? 0) + 1 });
24	    }
25	  }
26	  return tally;
27	}
28	
29	export function nextGeneration(cells: Cell[]): Cell[] {
30	  const liveKeys = new Set(cells.map(([x, y]) => keyOf(x, y)));
31	  const tally = tallyLiveNeighbors(cells);
32	
33	  const nextCells: Cell[] = [];
34	  for (const [key, { cell, liveNeighbors }] of tally) {
35	    if (survivesOrIsBorn(liveNeighbors, liveKeys.has(key))) {
36	      nextCells.push(cell);
37	    }
38	  }
39	  return nextCells;
40	}
